import React, { useState } from 'react'
import Card from './Card'

const BookingCard = ({ services }) => {
    const [query, setQuery] = useState("");

    return (
        <div>
            <div className='flex '>
                <input className='w-[300px] h-[30px]  bg-black p-2 text-white outline-none border-[1px] border-white rounded-md' placeholder="Enter type of service..." onChange={event => setQuery(event.target.value)} />
            </div>

            <div className='flex flex-wrap justify-center items-center gap-7'>
                {
                    services.length !== 0 ? (services
                        .filter(service => {
                            if (query === '') {
                                return service;
                            } else if (service.serviceType.toLowerCase().includes(query.toLowerCase())) {
                                return service;
                            }
                        })
                        .map((service, index) => (
                            <Card key={index} service={service} />))) :
                        (<div className='text-white text-2xl font-nunito'>No Data Found</div>)
                }
            </div>
        </div>
    )
}

export default BookingCard
